1	package federation
2	
3	import (
4		"encoding/json"
5		"errors"
6		"fmt"
7		"os"
8		"path/filepath"
9		"sync"
10	)
11	
12	// stateFileName is the on-disk filename, under XDG_DATA_HOME / ~/.local/share.
13	const stateFileName = "federation-state.json"
14	
15	// fileMode is mode 0600: registry may carry spoke URLs and identity, so it is
16	// owner-readable only (FEAT-026 NFR).
17	const fileMode os.FileMode = 0o600
18	
19	// dirMode for the parent directory.
20	const dirMode os.FileMode = 0o700
21	
22	// writeMu serializes concurrent SaveStateTo calls within one process so
23	// tmpfile+rename does not race against itself. (Cross-process safety relies
24	// on rename atomicity.)
25	var writeMu sync.Mutex
26	
27	// DefaultStatePath returns ~/.local/share/ddx/federation-state.json.
28	// Honors XDG_DATA_HOME when set, otherwise falls back to ~/.local/share.
29	func DefaultStatePath() (string, error) {
30		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
31			return filepath.Join(xdg, "ddx", stateFileName), nil
32		}
33		home, err := os.UserHomeDir()
34		if err != nil {
35			return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
36		}
37		return filepath.Join(home, ".local", "share", "ddx", stateFileName), nil
38	}
39	
40	// LoadState reads the registry from the default path.
41	func LoadState() (*FederationRegistry, error) {
42		path, err := DefaultStatePath()
43		if err != nil {
44			return nil, err
45		}
46		return LoadStateFrom(path)
47	}
48	
49	// SaveState writes the registry to the default path.
50	func SaveState(r *FederationRegistry) error {
51		path, err := DefaultStatePath()
52		if err != nil {
53			return err
54		}
55		return SaveStateTo(path, r)
56	}
57	
58	// LoadStateFrom reads the registry from path. Behavior:
59	//
60	//   - Missing file       → fresh empty registry stamped with CurrentSchemaVersion.
61	//   - Malformed JSON     → fresh empty registry; the corrupt file is renamed
62	//     to "<path>.corrupt-<ts>" so an operator can recover it.
63	//   - Unknown future     → loaded as-is; caller can inspect SchemaVersion and
64	//     schema_version       decide whether to refuse to write.
65	func LoadStateFrom(path string) (*FederationRegistry, error) {
66		data, err := os.ReadFile(path)
67		if errors.Is(err, os.ErrNotExist) {
68			return NewRegistry(), nil
69		}
70		if err != nil {
71			return nil, fmt.Errorf("federation: read state: %w", err)
72		}
73	
74		var reg FederationRegistry
75		if err := json.Unmarshal(data, &reg); err != nil {
76			// Quarantine the corrupt file so it's not silently overwritten on the
77			// next save, then return a fresh registry. This is the recovery path
78			// the bead's "malformed-file recovery" AC asks for.
79			_ = quarantineCorrupt(path)
80			return NewRegistry(), nil
81		}
82	
83		if reg.SchemaVersion == "" {
84			// Pre-versioned files are treated as v1; future migrations would key
85			// off the read SchemaVersion before this defaulting.
86			reg.SchemaVersion = CurrentSchemaVersion
87		}
88		if reg.Spokes == nil {
89			reg.Spokes = []SpokeRecord{}
90		}
91		return &reg, nil
92	}
93	
94	// SaveStateTo writes the registry to path atomically: marshal → write tmpfile
95	// in the same directory → fsync → rename onto the target. The rename is
96	// atomic on POSIX filesystems, so a partially-written file is never visible.
97	func SaveStateTo(path string, r *FederationRegistry) error {
98		if r == nil {
99			return fmt.Errorf("federation: nil registry")
100		}
101		if r.SchemaVersion == "" {
102			r.SchemaVersion = CurrentSchemaVersion
103		}
104		if r.Spokes == nil {
105			r.Spokes = []SpokeRecord{}
106		}
107	
108		writeMu.Lock()
109		defer writeMu.Unlock()
110	
111		if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
112			return fmt.Errorf("federation: mkdir: %w", err)
113		}
114	
115		data, err := json.MarshalIndent(r, "", "  ")
116		if err != nil {
117			return fmt.Errorf("federation: marshal: %w", err)
118		}
119	
120		tmp, err := os.CreateTemp(filepath.Dir(path), ".federation-state-*.json.tmp")
121		if err != nil {
122			return fmt.Errorf("federation: create tmpfile: %w", err)
123		}
124		tmpPath := tmp.Name()
125		cleanup := func() { _ = os.Remove(tmpPath) }
126	
127		if _, err := tmp.Write(data); err != nil {
128			_ = tmp.Close()
129			cleanup()
130			return fmt.Errorf("federation: write tmpfile: %w", err)
131		}
132		if err := tmp.Sync(); err != nil {
133			_ = tmp.Close()
134			cleanup()
135			return fmt.Errorf("federation: fsync tmpfile: %w", err)
136		}
137		if err := tmp.Close(); err != nil {
138			cleanup()
139			return fmt.Errorf("federation: close tmpfile: %w", err)
140		}
141		if err := os.Chmod(tmpPath, fileMode); err != nil {
142			cleanup()
143			return fmt.Errorf("federation: chmod tmpfile: %w", err)
144		}
145		if err := os.Rename(tmpPath, path); err != nil {
146			cleanup()
147			return fmt.Errorf("federation: rename: %w", err)
148		}
149		return nil
150	}
151	
152	func quarantineCorrupt(path string) error {
153		info, err := os.Stat(path)
154		if err != nil || info.IsDir() {
155			return err
156		}
157		bak := fmt.Sprintf("%s.corrupt-%d", path, info.ModTime().UnixNano())
158		return os.Rename(path, bak)
159	}
