3	// Federation resolvers (B14.6b). The hub fans out a small set of read-only
4	// queries to every active spoke via the B14.6a fan-out client, decorates
5	// each row with routing metadata (node_id, project_id, project_url,
6	// write_capability, status), and merges the per-spoke responses into a
7	// single result. Local query types (beads, runs, projects) are unchanged —
8	// these federated queries ship in parallel so existing local views keep
9	// working.
10	
11	import (
12		"context"
13		"encoding/json"
14		"strings"
15		"time"
16	
17		"github.com/DocumentDrivenDX/ddx/internal/federation"
18	)
19	
20	// FederationProvider exposes the hub-side state required by the federated
21	// query resolvers. The Resolver is wired with a nil provider on non-hub
22	// servers; resolvers degrade to empty-list responses in that case.
23	type FederationProvider interface {
24		// Spokes returns a snapshot of registered spokes. Implementations should
25		// return a copy that callers may sort or filter without affecting the
26		// underlying registry.
27		Spokes() []federation.SpokeRecord
28		// FanOut executes the supplied request against every spoke returned by
29		// Spokes (the implementation may apply its own active/stale policy) and
30		// returns the merged FanOutResult.
31		FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error)
32	}
33	
34	// federationCapWrite is the capability string a spoke advertises when it
35	// allows writes from federated callers. Read-only fan-out is the v1 default
36	// so this field is always false until a spoke explicitly opts in.
37	const federationCapWrite = "write"
38	
39	// federationIdentityPrefix mirrors the synthetic capability used by the hub
40	// to stash the identity fingerprint on a SpokeRecord. Filtered out of the
41	// FederationNode.capabilities surface so clients never see it.
42	const federationIdentityPrefix = "@identity:"
43	
44	// FederationNodes returns one row per registered spoke decorated with the
45	// most recent fan-out outcome. When the server is not in hub mode (Resolver
46	// has no FederationProvider) the result is an empty list.
47	func (r *queryResolver) FederationNodes(ctx context.Context) ([]*FederationNode, error) {
48		if r.Federation == nil {
49			return []*FederationNode{}, nil
50		}
51		spokes := r.Federation.Spokes()
52		out := make([]*FederationNode, 0, len(spokes))
53		for _, s := range spokes {
54			out = append(out, federationNodeFromSpoke(s, ""))
55		}
56		return out, nil
57	}
58	
59	// FederatedBeads fans out a beads query and merges the resulting edges into
60	// FederatedBead rows.
61	func (r *queryResolver) FederatedBeads(ctx context.Context, status *string, label *string, projectID *string) ([]*FederatedBead, error) {
62		if r.Federation == nil {
63			return []*FederatedBead{}, nil
64		}
65		const beadsQuery = `query FedBeads($status:String,$label:String,$projectID:String){
66	  beads(first:200,status:$status,label:$label,projectID:$projectID){
67	    edges{node{id title status priority issueType owner createdAt createdBy updatedAt labels projectID parent description acceptance notes}}
68	  }
69	}`
70		vars := map[string]any{}
71		if status != nil {
72			vars["status"] = *status
73		}
74		if label != nil {
75			vars["label"] = *label
76		}
77		if projectID != nil {
78			vars["projectID"] = *projectID
79		}
80		res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: beadsQuery, Variables: vars})
81		if err != nil {
82			return nil, err
83		}
84		spokeIndex := indexSpokes(r.Federation.Spokes())
85		out := []*FederatedBead{}
86		for _, n := range res.Nodes {
87			if n.Outcome != federation.OutcomeOK {
88				continue
89			}
90			var resp struct {
91				Data struct {
92					Beads struct {
93						Edges []struct {
94							Node *Bead `json:"node"`
95						} `json:"edges"`
96					} `json:"beads"`
97				} `json:"data"`
98			}
99			if err := json.Unmarshal(n.Response, &resp); err != nil {
100				continue
101			}
102			s := spokeIndex[n.NodeID]
103			writeCap := hasCapability(s.Capabilities, federationCapWrite)
104			statusStr := string(s.Status)
105			for _, e := range resp.Data.Beads.Edges {
106				if e.Node == nil {
107					continue
108				}
109				out = append(out, &FederatedBead{
110					NodeID:          n.NodeID,
111					ProjectID:       e.Node.ProjectID,
112					ProjectURL:      n.URL,
113					WriteCapability: writeCap,
114					Status:          statusStr,
115					Bead:            e.Node,
116				})
117			}
118		}
119		return out, nil
120	}
