122	// FederatedRuns fans out a runs query and merges the resulting edges into
123	// FederatedRun rows.
124	func (r *queryResolver) FederatedRuns(ctx context.Context, layer *RunLayer, projectID *string) ([]*FederatedRun, error) {
125		if r.Federation == nil {
126			return []*FederatedRun{}, nil
127		}
128		const runsQuery = `query FedRuns($layer:RunLayer,$projectID:String){
129	  runs(first:200,layer:$layer,projectID:$projectID){
130	    edges{node{id layer status projectID startedAt completedAt beadId artifactId parentRunId childRunIds}}
131	  }
132	}`
133		vars := map[string]any{}
134		if layer != nil {
135			vars["layer"] = string(*layer)
136		}
137		if projectID != nil {
138			vars["projectID"] = *projectID
139		}
140		res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: runsQuery, Variables: vars})
141		if err != nil {
142			return nil, err
143		}
144		spokeIndex := indexSpokes(r.Federation.Spokes())
145		out := []*FederatedRun{}
146		for _, n := range res.Nodes {
147			if n.Outcome != federation.OutcomeOK {
148				continue
149			}
150			var resp struct {
151				Data struct {
152					Runs struct {
153						Edges []struct {
154							Node *Run `json:"node"`
155						} `json:"edges"`
156					} `json:"runs"`
157				} `json:"data"`
158			}
159			if err := json.Unmarshal(n.Response, &resp); err != nil {
160				continue
161			}
162			s := spokeIndex[n.NodeID]
163			writeCap := hasCapability(s.Capabilities, federationCapWrite)
164			statusStr := string(s.Status)
165			for _, e := range resp.Data.Runs.Edges {
166				if e.Node == nil {
167					continue
168				}
169				out = append(out, &FederatedRun{
170					NodeID:          n.NodeID,
171					ProjectID:       e.Node.ProjectID,
172					ProjectURL:      n.URL,
173					WriteCapability: writeCap,
174					Status:          statusStr,
175					Run:             e.Node,
176				})
177			}
178		}
179		return out, nil
180	}
181	
182	// FederatedProjects fans out a projects query and merges the resulting edges
183	// into FederatedProject rows.
184	func (r *queryResolver) FederatedProjects(ctx context.Context, includeUnreachable *bool) ([]*FederatedProject, error) {
185		if r.Federation == nil {
186			return []*FederatedProject{}, nil
187		}
188		const projectsQuery = `query FedProjects($inc:Boolean){
189	  projects(first:200,includeUnreachable:$inc){
190	    edges{node{id name path gitRemote registeredAt lastSeen unreachable tombstonedAt}}
191	  }
192	}`
193		vars := map[string]any{}
194		if includeUnreachable != nil {
195			vars["inc"] = *includeUnreachable
196		}
197		res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: projectsQuery, Variables: vars})
198		if err != nil {
199			return nil, err
200		}
201		spokeIndex := indexSpokes(r.Federation.Spokes())
202		out := []*FederatedProject{}
203		for _, n := range res.Nodes {
204			if n.Outcome != federation.OutcomeOK {
205				continue
206			}
207			var resp struct {
208				Data struct {
209					Projects struct {
210						Edges []struct {
211							Node *Project `json:"node"`
212						} `json:"edges"`
213					} `json:"projects"`
214				} `json:"data"`
215			}
216			if err := json.Unmarshal(n.Response, &resp); err != nil {
217				continue
218			}
219			s := spokeIndex[n.NodeID]
220			writeCap := hasCapability(s.Capabilities, federationCapWrite)
221			statusStr := string(s.Status)
222			for _, e := range resp.Data.Projects.Edges {
223				if e.Node == nil {
224					continue
225				}
226				out = append(out, &FederatedProject{
227					NodeID:          n.NodeID,
228					ProjectID:       e.Node.ID,
229					ProjectURL:      n.URL,
230					WriteCapability: writeCap,
231					Status:          statusStr,
232					Project:         e.Node,
233				})
234			}
235		}
236		return out, nil
237	}
238	
239	// federationNodeFromSpoke materializes one FederationNode row, filtering the
240	// synthetic identity capability and stamping a lastError diagnostic when
241	// supplied (e.g. for a version-skew handshake).
242	func federationNodeFromSpoke(s federation.SpokeRecord, lastError string) *FederationNode {
243		caps := make([]string, 0, len(s.Capabilities))
244		for _, c := range s.Capabilities {
245			if strings.HasPrefix(c, federationIdentityPrefix) {
246				continue
247			}
248			caps = append(caps, c)
249		}
250		n := &FederationNode{
251			ID:              s.NodeID,
252			NodeID:          s.NodeID,
253			Name:            s.Name,
254			URL:             s.URL,
255			Status:          string(s.Status),
256			DdxVersion:      s.DDxVersion,
257			SchemaVersion:   s.SchemaVersion,
258			Capabilities:    caps,
259			RegisteredAt:    s.RegisteredAt.UTC().Format(time.RFC3339),
260			WriteCapability: hasCapability(caps, federationCapWrite),
261		}
262		if !s.LastHeartbeat.IsZero() {
263			ts := s.LastHeartbeat.UTC().Format(time.RFC3339)
264			n.LastHeartbeat = &ts
265		}
266		if lastError != "" {
267			le := lastError
268			n.LastError = &le
269		}
270		return n
271	}
272	
273	func hasCapability(caps []string, want string) bool {
274		for _, c := range caps {
275			if c == want {
276				return true
277			}
278		}
279		return false
280	}
281	
282	func indexSpokes(spokes []federation.SpokeRecord) map[string]federation.SpokeRecord {
283		out := make(map[string]federation.SpokeRecord, len(spokes))
284		for _, s := range spokes {
285			out[s.NodeID] = s
286		}
287		return out
288	}
