3	// Lint test for ddx-15f7ee0b Fix A: every test file in this package (and
4	// adjacent directories that wire up ServerState) that constructs a server or
5	// loads a ServerState must point the state directory at an isolated location.
6	// Tests that skip this leak phantom project entries into the developer's real
7	// ~/.local/share/ddx/server-state.json.
8	//
9	// The check is intentionally conservative: a function that calls any of the
10	// "constructor" set below must also invoke at least one of the "isolation"
11	// set. Adding a new helper that internally isolates XDG_DATA_HOME is the
12	// preferred way to keep this passing.
13	
14	import (
15		"go/ast"
16		"go/parser"
17		"go/token"
18		"io/fs"
19		"path/filepath"
20		"strings"
21		"testing"
22	)
23	
24	// constructorNames are function calls that build a server or directly load a
25	// ServerState. Any test that touches one of these must also pick up isolation.
26	// Entries without a "pkg." prefix match only package-local calls; entries like
27	// "server.New" match explicit cross-package qualified references.
28	var constructorNames = map[string]bool{
29		"New":               true,
30		"server.New":        true,
31		"loadServerState":   true,
32		"ListenAndServe":    true,
33		"ListenAndServeTLS": true,
34	}
35	
36	// isolationHelpers are helpers (defined in this package or adjacent test
37	// helpers) that set XDG_DATA_HOME before any server is created. A call to
38	// any of them satisfies the lint rule.
39	var isolationHelpers = map[string]bool{
40		"setupTestDir":               true,
41		"setupNodeTestDir":           true,
42		"setupProcessMetricsTestDir": true,
43		"setupDocTestDir":            true,
44		"setupExecTestDir":           true,
45		"setupGitTestDir":            true,
46		"setupProjectWithBeads":      true,
47		"setupBeadLookupFixture":     true,
48		"BuildBeadFixture":           true,
49	}
50	
51	// TestTestsIsolateStateDir walks the Go test files in the server package and
52	// perf sub-package, and asserts that every test (or benchmark) function that
53	// wires up a server also isolates XDG_DATA_HOME. See ddx-15f7ee0b Fix A.
54	func TestTestsIsolateStateDir(t *testing.T) {
55		err := filepath.WalkDir(".", func(path string, d fs.DirEntry, err error) error {
56			if err != nil {
57				return err
58			}
59			if d.IsDir() {
60				switch d.Name() {
61				case "frontend", "node_modules", ".svelte-kit", "build":
62					return filepath.SkipDir
63				default:
64					return nil
65				}
66			}
67			if strings.HasSuffix(d.Name(), "_test.go") {
68				lintTestFile(t, path)
69			}
70			return nil
71		})
72		if err != nil {
73			t.Fatalf("walk server tests: %v", err)
74		}
75	}
76	
77	func lintTestFile(t *testing.T, path string) {
78		t.Helper()
79		fset := token.NewFileSet()
80		file, err := parser.ParseFile(fset, path, nil, parser.SkipObjectResolution)
81		if err != nil {
82			t.Fatalf("parse %s: %v", path, err)
83		}
84	
85		// Skip the lint test file itself — it is allowed to reference constructor
86		// names inside string maps without wiring up a server.
87		if strings.HasSuffix(path, "/test_isolation_lint_test.go") {
88			return
89		}
90	
91		for _, decl := range file.Decls {
92			fn, ok := decl.(*ast.FuncDecl)
93			if !ok || fn.Body == nil {
94				continue
95			}
96			// Only audit functions that could contain test code — Test*, Benchmark*,
97			// or helpers used by such functions. For simplicity, audit all fns in
98			// _test.go files. Helpers that unconditionally call setupTestDir etc.
99			// will pass trivially.
100			hasCtor := false
101			hasIso := false
102			ast.Inspect(fn.Body, func(n ast.Node) bool {
103				call, ok := n.(*ast.CallExpr)
104				if !ok {
105					return true
106				}
107				name := callName(call.Fun)
108				if constructorNames[name] {
109					hasCtor = true
110				}
111				if isolationHelpers[name] {
112					hasIso = true
113				}
114				// Detect raw XDG_DATA_HOME sets: any call with a first arg that is
115				// the string literal "XDG_DATA_HOME".
116				if name == "Setenv" || name == "t.Setenv" {
117					// argList: check any arg is "XDG_DATA_HOME"
118					for _, a := range call.Args {
119						if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
120							if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
121								hasIso = true
122							}
123						}
124					}
125				}
126				return true
127			})
128	
129			if hasCtor && !hasIso {
130				t.Errorf("%s: function %s constructs a server without isolating XDG_DATA_HOME — call setupTestDir/etc. or t.Setenv(\"XDG_DATA_HOME\", ...) before building the server (ddx-15f7ee0b Fix A)",
131					path, fn.Name.Name)
132			}
133		}
134	}
135	
136	// callName returns one of three things:
137	//   - For `Foo(...)`:         "Foo"
138	//   - For `pkg.Foo(...)`:     "pkg.Foo"
139	//   - For `t.Setenv(...)`:    "Setenv"  (receiver is a local identifier, not
140	//     a package — we only add the prefix when the
141	//     receiver looks like a package name, i.e.
142	//     lowercase and short; this is a heuristic.)
143	//
144	// Having qualified names lets the constructor list distinguish server.New
145	// from handler.New without false positives.
146	func callName(fn ast.Expr) string {
147		switch v := fn.(type) {
148		case *ast.Ident:
149			return v.Name
150		case *ast.SelectorExpr:
151			if pkg, ok := v.X.(*ast.Ident); ok {
152				// Heuristic: treat short lowercase identifiers as package names.
153				// Receivers like `t`, `srv`, `w` fall through — we still want
154				// Setenv to match for `t.Setenv(...)`. The Setenv match is
155				// special-cased by the lint body; the selector branch here just
156				// carries the package-qualified form when it looks right.
157				if looksLikePackageName(pkg.Name) {
158					return pkg.Name + "." + v.Sel.Name
159				}
160			}
161			return v.Sel.Name
162		}
163		return ""
164	}
165	
166	// looksLikePackageName is a heuristic for callName: longer-than-2 lowercase
167	// identifiers are treated as package-like (so "server.New" is distinguished
168	// from "srv.Shutdown"). Receivers like t, s, srv, b, tb return false.
169	func looksLikePackageName(s string) bool {
170		if len(s) < 3 {
171			return false
172		}
173		for _, r := range s {
174			if r < 'a' || r > 'z' {
175				return false
176			}
177		}
178		// Reject common local-variable names that happen to be lowercase words.
179		switch s {
180		case "srv", "tb", "ctx", "err", "req", "res":
181			return false
182		}
183		return true
184	}
185	
186	// TestTestIsolationLintCatchesBadCase is a meta-test: it feeds the linter a
187	// synthetic "bad" file and asserts the linter flags it. Covers the
188	// "disallowed-pattern" arm of ddx-15f7ee0b Fix A.
189	func TestTestIsolationLintCatchesBadCase(t *testing.T) {
190		badSource := `package server
191	
192	import "testing"
193	
194	func TestBadlyIsolatedExample(t *testing.T) {
195		srv := New(":0", "/tmp/ignored")
196		_ = srv
197	}
198	`
199		goodSource := `package server
200	
201	import "testing"
202	
203	func TestProperlyIsolatedExample(t *testing.T) {
204		t.Setenv("XDG_DATA_HOME", t.TempDir())
205		srv := New(":0", "/tmp/ignored")
206		_ = srv
207	}
208	`
209		if got := lintSourceString(badSource); got == nil {
210			t.Error("expected bad source to be flagged by lint, got nil")
211		}
212		if got := lintSourceString(goodSource); got != nil {
213			t.Errorf("expected good source to pass lint, got error: %v", got)
214		}
215	}
216	
217	// lintSourceString runs the same AST walk on an in-memory source string and
218	// returns a non-nil error if the lint would have failed. Used by the meta-test.
219	func lintSourceString(src string) error {
220		fset := token.NewFileSet()
221		file, err := parser.ParseFile(fset, "synthetic.go", src, parser.SkipObjectResolution)
222		if err != nil {
223			return err
224		}
225		for _, decl := range file.Decls {
226			fn, ok := decl.(*ast.FuncDecl)
227			if !ok || fn.Body == nil {
228				continue
229			}
230			hasCtor := false
231			hasIso := false
232			ast.Inspect(fn.Body, func(n ast.Node) bool {
233				call, ok := n.(*ast.CallExpr)
234				if !ok {
235					return true
236				}
237				name := callName(call.Fun)
238				if constructorNames[name] {
239					hasCtor = true
240				}
241				if isolationHelpers[name] {
242					hasIso = true
243				}
244				if name == "Setenv" {
245					for _, a := range call.Args {
246						if lit, ok := a.(*ast.BasicLit); ok && lit.Kind == token.STRING {
247							if strings.Trim(lit.Value, "`\"") == "XDG_DATA_HOME" {
248								hasIso = true
249							}
250						}
251					}
252				}
253				return true
254			})
255			if hasCtor && !hasIso {
256				return &lintErr{msg: fn.Name.Name + " constructs server without isolation"}
257			}
258		}
259		return nil
260	}
261	
262	type lintErr struct{ msg string }
263	
264	func (e *lintErr) Error() string { return e.msg }
